          // ?щ쭩?섏? ?딆븯?붾씪??洹??섏쐞(?먯넀)???щ쭩?먭? ?덉쓣 ???덉쑝誘濡??먯깋
          visit(h, currentLevel + 1);
        }
      });
    };
    
    visit(tree, 1);
    return Array.from(tabMap.values());
  }, [tree]);

